// Early exit for configurator open event - no Claude call needed
if ($json.message === '__configurator_open__') {
  return [{
    json: {
      ...$json,
      _configurator_line: $json.configurator_line || 'unknown',
      _skip_claude: true,
      _event_type: 'configurator_open'
    }
  }];
}

const body = $input.first().json.body;
const headers = $input.first().json.headers;

// Auth check
const token = 'eac10535d2bbaaa3e3aedda46b556db6';
if (headers['x-widget-token'] !== token) {
  throw new Error('UNAUTHORIZED');
}

// Validate
if (!body.message || body.message.length === 0 || body.message.length > 1000) {
  throw new Error('Invalid message');
}
if (!body.session_id) {
  throw new Error('session_id required');
}
if (body.consent !== true) {
  throw new Error('Consent required');
}

// Simple IP hash
const ip = headers['x-forwarded-for'] || headers['x-real-ip'] || 'unknown';
const ipHash = ip.replace(/\\./g, '-');

// Business hours (Europe/Vienna)
const wienTime = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Vienna' }));
const hour = wienTime.getHours();
const day = wienTime.getDay();
const isBusinessHours = (day >= 1 && day <= 5 && hour >= 8 && hour < 17);

return [{
  json: {
    session_id: body.session_id,
    message: body.message,
    ipHash,
    consent: body.consent,
    page_url: body.page_url || '',
    user_agent: headers['user-agent'] || '',
    is_business_hours: isBusinessHours,
    source_type: body.source_type || 'typed'
  }
}];

const sessionId = $('Build Claude Payload').first().json._session_id;
const userMessage = $('Build Claude Payload').first().json._user_message;
const leadStep = $('Build Claude Payload').first().json._lead_step || 0;
const collectedData = $('Build Claude Payload').first().json._collected_data || {};

return [{
  json: {
    content: [{ type: 'text', text: 'Unser Sonnenschutz-Berater ist gerade nicht erreichbar. Bitte kontaktieren Sie uns direkt unter +43 1 212 2446 oder per E-Mail an team@rollomax.at. Wir helfen Ihnen gerne persönlich weiter.' }],
    _session_id: sessionId,
    _user_message: userMessage,
    _is_fallback: true,
    _is_business_hours: $('Build Claude Payload').first().json._is_business_hours || false,
    _source_type: $('Build Claude Payload').first().json._source_type || 'typed',
    _lead_step: leadStep,
    _collected_data: collectedData
  }
}];

const input = $input.first().json;
const sessionId = input._session_id || $('Build Claude Payload').first().json._session_id;
const userMessage = input._user_message || $('Build Claude Payload').first().json._user_message;
const isBusinessHours = input._is_business_hours || $('Build Claude Payload').first().json._is_business_hours || false;
const sourceType = input._source_type || $('Build Claude Payload').first().json._source_type || 'typed';
const currentLeadStep = $('Build Claude Payload').first().json._lead_step || 0;
const currentCollectedData = $('Build Claude Payload').first().json._collected_data || {};

let responseText = '';
if (input._is_fallback) {
  responseText = input.content[0].text;
  return [{ json: {
    reply: responseText,
    session_id: sessionId,
    user_message: userMessage,
    intent: 'general',
    has_lead_data: false,
    lead_data: null,
    should_notify_team: false,
    urgency: 'low',
    is_business_hours: isBusinessHours,
    source_type: sourceType,
    show_product_card: null,
    show_actions: [],
    new_lead_step: currentLeadStep,
    new_collected_data: currentCollectedData
  }}];
}

responseText = input.content[0].text;

// Versuch 1: Strukturiertes JSON mit Delimiter
const jsonMatch = responseText.match(/<<<RESPONSE_JSON>>>([\s\S]*?)<<<END_RESPONSE_JSON>>>/);
let parsed = null;

if (jsonMatch) {
  try {
    parsed = JSON.parse(jsonMatch[1].trim());
  } catch(e) {
    parsed = null;
  }
}

// Versuch 2: Legacy LEAD-Format (Rueckwaertskompatibilitaet)
if (!parsed) {
  const leadMatch = responseText.match(/<!--LEAD:(.*?)-->/);
  let legacyLead = null;
  let cleanReply = responseText;
  if (leadMatch) {
    try { legacyLead = JSON.parse(leadMatch[1]); } catch(e) {}
    cleanReply = responseText.replace(/<!--LEAD:.*?-->/, '').trim();
  }
  parsed = {
    reply: cleanReply,
    intent: 'general',
    lead_data: legacyLead,
    should_notify_team: false,
    urgency: 'low',
    show_product_card: null,
    show_actions: []
  };
}

// Calculate new lead step based on lead_data
let newCollectedData = { ...currentCollectedData };
let newLeadStep = currentLeadStep;
const ld = parsed.lead_data || {};

if (ld.interest && !newCollectedData.product) {
  newCollectedData.product = ld.interest;
  if (newLeadStep < 1) newLeadStep = 1;
}
if (ld.plz && !newCollectedData.location) {
  newCollectedData.location = ld.plz;
  if (newLeadStep < 2) newLeadStep = 2;
}
if (ld.customer_type && !newCollectedData.customer_type) {
  newCollectedData.customer_type = ld.customer_type;
  if (newLeadStep < 3) newLeadStep = 3;
}
if (ld.project_type && !newCollectedData.project_type) {
  newCollectedData.project_type = ld.project_type;
  if (newLeadStep < 4) newLeadStep = 4;
}
if (ld.scope && !newCollectedData.scope) {
  newCollectedData.scope = ld.scope;
  if (newLeadStep < 5) newLeadStep = 5;
}
if ((ld.name || ld.phone || ld.email) && !newCollectedData.contact) {
  const parts = [];
  if (ld.name) parts.push(ld.name);
  if (ld.phone) parts.push(ld.phone);
  if (ld.email) parts.push(ld.email);
  newCollectedData.contact = parts.join(', ');
  if (newLeadStep < 6) newLeadStep = 6;
}

return [{ json: {
  reply: parsed.reply || responseText,
  session_id: sessionId,
  user_message: userMessage,
  intent: parsed.intent || 'general',
  has_lead_data: parsed.lead_data !== null && parsed.lead_data !== undefined,
  lead_data: parsed.lead_data || null,
  should_notify_team: parsed.should_notify_team || false,
  urgency: parsed.urgency || 'low',
  is_business_hours: isBusinessHours,
  source_type: sourceType,
  show_product_card: parsed.show_product_card || null,
  show_actions: parsed.show_actions || [],
  new_lead_step: newLeadStep,
  new_collected_data: newCollectedData
}}];

const data = $input.first().json;
const intent = data.intent || 'general';
const hasLeadData = data.has_lead_data || false;
const isBusinessHours = data.is_business_hours || false;

let suggestedActions = [];

switch(intent) {
  case 'product_inquiry':
    suggestedActions = ['Kostenlose Beratung anfragen', 'Foerderung pruefen'];
    break;
  case 'price_question':
    suggestedActions = ['Kostenloses Aufmass anfragen', 'Beratungstermin vereinbaren'];
    break;
  case 'booking_request':
    if (isBusinessHours) {
      suggestedActions = ['Jetzt anrufen: +43 1 212 2446'];
    } else {
      suggestedActions = ['Kontaktdaten hinterlassen', 'E-Mail schreiben'];
    }
    break;
  case 'complaint':
    suggestedActions = ['Rueckruf anfordern'];
    break;
  case 'general':
    suggestedActions = ['Beratungstermin vereinbaren'];
    break;
  case 'off_topic':
    suggestedActions = ['Sonnenschutz-Beratung starten'];
    break;
  default:
    suggestedActions = [];
}

if (hasLeadData) {
  suggestedActions = ['Vielen Dank - wir melden uns!'];
}

return [{ json: { ...data, suggested_actions: suggestedActions } }];

const data = $input.first().json;
const leadData = data.lead_data || {};
const lines = [
  'NEUER LEAD bei RolloMax Chat!',
  '',
  'Dringlichkeit: ' + (data.urgency || 'unbekannt'),
  'Intent: ' + (data.intent || 'unbekannt'),
  'Interesse: ' + (leadData.interest || 'Nicht angegeben'),
  'Name: ' + (leadData.name || 'Unbekannt'),
  'Telefon: ' + (leadData.phone || '-'),
  'E-Mail: ' + (leadData.email || '-'),
  'PLZ: ' + (leadData.plz || '-'),
  '',
  'Letzte Nachricht: ' + (data.user_message || '-')
];

return [{ json: {
  alert_text: lines.join('\n'),
  session_id: data.session_id,
  lead_data: data.lead_data
}}];
